def parse_config(input_str):
    """
    Parse a configuration string into a list of dictionaries.

    Args:
        input_str (str): The input configuration string.

    Returns:
        list: A list of dictionaries representing the parsed configuration.
        |Dict: 'assignment' or 'block' format.
    """

    lines = input_str.replace("{}", "").replace("{",":")[1:].split("}")
    config = {}
    block_name = None
    for line in lines:
        if line == "BLOCK":
            block_name = line.upper()[5:]
            config[block_name] = config.get(block_name, [])
        elif line == "}":
            continue
        elif line == "SET":
            config[block_name].append({"type": "assignment", "key": line.split("=")[0].strip(), "value": line.split("=")[1].strip()})
        elif line == "END":
            continue
        elif line == "BLOCK":
            config[block_name].append({"type": "block", "name": block_name})
        else:
            config[block_name].append({"type": "assignment", "key": line.strip(), "value": None})
    return config
